import { DirectUpload } from '@rails/activestorage';

export const readCookie = (name: string) => {
  var nameEQ = name + '=';
  var ca = document.cookie.split(';');
  for (var i = 0; i < ca.length; i++) {
    var c = ca[i];
    while (c.charAt(0) === ' ') c = c.substring(1, c.length);
    if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
  }
  return null;
};

const doDirectUpload = (
  file: any,
  abortSignal?: AbortSignal,
  cb?: (progressEvent: any) => void
) => {
  return new Promise((resolve, reject) => {
    const du = new DirectUpload(file, `/rails/active_storage/direct_uploads`, {
      directUploadWillCreateBlobWithXHR: (xhr: any) => {
        const csrfToken = decodeURIComponent(
          readCookie('X-CSRF-TOKEN') as string
        );
        xhr.setRequestHeader('X-CSRF-TOKEN', csrfToken);
        xhr.withCredentials = true;
      },
      directUploadWillStoreFileWithXHR(xhr) {
        abortSignal &&
          abortSignal.addEventListener('abort', () => {
            //
            xhr.abort();
            xhr.upload.removeEventListener('progress', onProgress);
          });
        const onProgress = progressEvent => {
          cb && cb(progressEvent);
        };

        xhr.upload.addEventListener('progress', onProgress);
      },
    });
    du.create((error: any, blob: any) => {
      if (error) {
        reject(error);
      } else {
        resolve(blob.signed_id);
      }
    });
  });
};

